import{_ as i}from"./chunks/pricing.xnwHCEuz.js";import{_ as a,o as s,c as n,a2 as l}from"./chunks/framework.BflysNKA.js";const _=JSON.parse('{"title":"Gemini CLI","description":"","frontmatter":{},"headers":[],"relativePath":"tools/gemini-cli.md","filePath":"tools/gemini-cli.md","lastUpdated":1778577020000}'),p={name:"tools/gemini-cli.md"};function t(o,e,c,d,r,m){return s(),n("div",null,[...e[0]||(e[0]=[l(`<h1 id="gemini-cli" tabindex="-1">Gemini CLI <a class="header-anchor" href="#gemini-cli" aria-label="Permalink to &quot;Gemini CLI&quot;">​</a></h1><p>Gemini CLI 适合长文总结、大仓库阅读和长上下文场景。</p><p>如果你要把 Gemini CLI 接到 小蓝中转站，优先看：<a href="/deploy/gemini-cli">Gemini CLI 部署</a>。</p><p>第一次配置时，重点先看这几件事：</p><ul><li><code>npx</code> 试用和全局安装的区别</li><li><code>GOOGLE_GEMINI_BASE_URL</code>、<code>GEMINI_API_KEY</code>、<code>GEMINI_MODEL</code> 该怎么填</li><li>为什么 Gemini CLI 填根地址 <code>https://xiaolan1.cn</code>，而不是 <code>/v1</code></li><li>第一次测试时为什么先用轻量模型</li><li>环境变量写好后要怎么验证是否已经生效</li><li>遇到回复慢或模型不存在时怎么排查</li></ul><p>Gemini CLI 这里最容易记错的一点是地址。<br> 它走的是 Gemini API 协议，所以这里写的是根地址：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>不是 <code>https://xiaolan1.cn/v1</code>。<br> CLI 会自己继续拼接 <code>/v1beta/models/...</code> 这类 Gemini API 路径。</p><p>第一次接入时，先记住这三项：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>GOOGLE_GEMINI_BASE_URL=https://xiaolan1.cn</span></span>
<span class="line"><span>GEMINI_API_KEY=sk-你的专属Key</span></span>
<span class="line"><span>GEMINI_MODEL=从模型广场复制的模型名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>模型切换常见有三种方式：</p><ul><li><code>GEMINI_MODEL</code>：给终端环境设置默认模型</li><li><code>gemini --model ...</code>：只影响这一次启动</li><li><code>/model</code>：进入 Gemini CLI 后临时切换</li></ul><p>真正算接通时，通常要同时满足：</p><ol><li><code>gemini</code> 命令能正常启动</li><li>发一句短消息后能正常返回</li><li>当前读到的是 小蓝中转站 根地址和你的 小蓝中转站 Key</li><li>当前模型确实是你刚配置的那个</li></ol><p>很多“明明已经装好了”的问题，最后都不是安装层，而是地址写成了 <code>/v1</code>、模型名来自旧教程，或者项目目录里还有额外的 <code>.gemini</code> 配置覆盖默认值。</p><p>如果你还在准备基础环境，先回 <a href="/guide/quick-start">快速接入</a> 按顺序完成账号、Key 和模型配置。</p><p>Key 在控制台侧边栏 <strong>API 密钥</strong> 创建，模型名从<strong>模型广场</strong>复制：</p><p><img src="`+i+'" alt="模型广场 — 找到目标模型，点击名称复制"></p><p>继续看：</p><ul><li>完整安装与环境变量写法： <a href="/deploy/gemini-cli">Gemini CLI 部署</a></li><li>还没准备终端环境： <a href="/beginner/windows">Windows 快速接入</a> / <a href="/beginner/macos">macOS 快速接入</a></li><li>想用图形界面统一管理 CLI： <a href="/tools/cc-switch">CC-Switch</a></li></ul>',20)])])}const g=a(p,[["render",t]]);export{_ as __pageData,g as default};
